import{_ as e,o as a,c as r,ag as d}from"./chunks/framework.6MCaaFDc.js";const b=JSON.parse('{"title":"Data Representation","description":"","frontmatter":{},"headers":[],"relativePath":"theory/systems/data-representation.md","filePath":"theory/systems/data-representation.md"}'),s={name:"theory/systems/data-representation.md"};function n(o,t,i,l,c,p){return a(),r("div",null,[...t[0]||(t[0]=[d(`<h1 id="data-representation" tabindex="-1">Data Representation <a class="header-anchor" href="#data-representation" aria-label="Permalink to &quot;Data Representation&quot;">​</a></h1><p>Inside a computer, everything is stored as binary — sequences of 0s and 1s. Letters, images, sounds, and instructions are all represented this way. Understanding how data is encoded into binary is fundamental to understanding how computers work.</p><div class="note custom-block github-alert"><p class="custom-block-title">Grade 10+</p><p>Binary and ASCII are introduced in Grade 10. Hexadecimal and Unicode extend into Grade 11. Number conversions are examined in both Paper 1 and Paper 2.</p></div><hr><h2 id="why-binary" tabindex="-1">Why Binary? <a class="header-anchor" href="#why-binary" aria-label="Permalink to &quot;Why Binary?&quot;">​</a></h2><p>Computers are built from transistors — electronic switches that are either ON (1) or OFF (0). Binary (base-2) maps perfectly to this: 1 = ON, 0 = OFF.</p><p>Every piece of data in a computer — text, images, audio, video, program instructions — is ultimately stored as a sequence of 0s and 1s.</p><hr><h2 id="number-systems-overview" tabindex="-1">Number Systems Overview <a class="header-anchor" href="#number-systems-overview" aria-label="Permalink to &quot;Number Systems Overview&quot;">​</a></h2><table tabindex="0"><thead><tr><th>System</th><th>Base</th><th>Digits</th><th>Used for</th></tr></thead><tbody><tr><td><strong>Decimal</strong></td><td>10</td><td>0–9</td><td>Human everyday counting</td></tr><tr><td><strong>Binary</strong></td><td>2</td><td>0, 1</td><td>Computer storage and processing</td></tr><tr><td><strong>Hexadecimal</strong></td><td>16</td><td>0–9, A–F</td><td>Compact representation of binary; memory addresses, colours</td></tr></tbody></table><hr><h2 id="binary-base-2" tabindex="-1">Binary (Base-2) <a class="header-anchor" href="#binary-base-2" aria-label="Permalink to &quot;Binary (Base-2)&quot;">​</a></h2><p>Each position represents a power of 2:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Position:  8    7    6    5    4    3    2    1</span></span>
<span class="line"><span>Power:    2⁷  2⁶  2⁵  2⁴  2³  2²  2¹  2⁰</span></span>
<span class="line"><span>Value:    128   64   32   16    8    4    2    1</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p><strong>Key powers of 2 to memorise:</strong></p><table tabindex="0"><thead><tr><th>Power</th><th>Value</th></tr></thead><tbody><tr><td>2⁰</td><td>1</td></tr><tr><td>2¹</td><td>2</td></tr><tr><td>2²</td><td>4</td></tr><tr><td>2³</td><td>8</td></tr><tr><td>2⁴</td><td>16</td></tr><tr><td>2⁵</td><td>32</td></tr><tr><td>2⁶</td><td>64</td></tr><tr><td>2⁷</td><td>128</td></tr><tr><td>2⁸</td><td>256</td></tr><tr><td>2¹⁰</td><td>1 024</td></tr></tbody></table><h3 id="binary-→-decimal" tabindex="-1">Binary → Decimal <a class="header-anchor" href="#binary-→-decimal" aria-label="Permalink to &quot;Binary → Decimal&quot;">​</a></h3><p>Multiply each bit by its place value and add:</p><p><code>10110101</code> = 128 + 32 + 16 + 4 + 1 = <strong>181</strong></p><h3 id="decimal-→-binary" tabindex="-1">Decimal → Binary <a class="header-anchor" href="#decimal-→-binary" aria-label="Permalink to &quot;Decimal → Binary&quot;">​</a></h3><p>Divide by 2 repeatedly; read remainders bottom to top:</p><p>45 ÷ 2 = 22 r <strong>1</strong><br> 22 ÷ 2 = 11 r <strong>0</strong><br> 11 ÷ 2 = 5 r <strong>1</strong><br> 5 ÷ 2 = 2 r <strong>1</strong><br> 2 ÷ 2 = 1 r <strong>0</strong><br> 1 ÷ 2 = 0 r <strong>1</strong></p><p>Read bottom to top: <strong>101101</strong></p><p>Verify: 32 + 8 + 4 + 1 = 45 ✓</p><hr><h2 id="hexadecimal-base-16" tabindex="-1">Hexadecimal (Base-16) <a class="header-anchor" href="#hexadecimal-base-16" aria-label="Permalink to &quot;Hexadecimal (Base-16)&quot;">​</a></h2><p>16 digits: 0–9 and A (10), B (11), C (12), D (13), E (14), F (15)</p><p>Each hex digit = exactly <strong>4 binary bits</strong> (one nibble).</p><p><strong>Hex → Binary shortcut:</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>A      F      3</span></span>
<span class="line"><span>1010  1111  0011</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>So <code>AF3₁₆ = 101011110011₂</code></p><p><strong>Binary → Hex shortcut:</strong></p><p>Group bits into 4 from the right, convert each group:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1101  0110</span></span>
<span class="line"><span>  D     6</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>So <code>11010110₂ = D6₁₆</code></p><h3 id="hex-→-decimal" tabindex="-1">Hex → Decimal <a class="header-anchor" href="#hex-→-decimal" aria-label="Permalink to &quot;Hex → Decimal&quot;">​</a></h3><p>Multiply each digit by its place value (power of 16):</p><p><code>2B₁₆</code> = (2 × 16) + (11 × 1) = 32 + 11 = <strong>43</strong></p><p><code>FF₁₆</code> = (15 × 16) + (15 × 1) = 240 + 15 = <strong>255</strong></p><h3 id="decimal-→-hex" tabindex="-1">Decimal → Hex <a class="header-anchor" href="#decimal-→-hex" aria-label="Permalink to &quot;Decimal → Hex&quot;">​</a></h3><p>Divide by 16 repeatedly:</p><p>255 ÷ 16 = 15 r <strong>15 (F)</strong><br> 15 ÷ 16 = 0 r <strong>15 (F)</strong></p><p>Bottom to top: <strong>FF</strong></p><hr><h2 id="ascii-—-encoding-text" tabindex="-1">ASCII — Encoding Text <a class="header-anchor" href="#ascii-—-encoding-text" aria-label="Permalink to &quot;ASCII — Encoding Text&quot;">​</a></h2><p><strong>ASCII</strong> (American Standard Code for Information Interchange) assigns a number to each character. The computer stores that number in binary.</p><p><strong>Key ASCII values:</strong></p><table tabindex="0"><thead><tr><th>Decimal</th><th>Hex</th><th>Character</th></tr></thead><tbody><tr><td>32</td><td>20</td><td>Space</td></tr><tr><td>48</td><td>30</td><td>&#39;0&#39;</td></tr><tr><td>57</td><td>39</td><td>&#39;9&#39;</td></tr><tr><td>65</td><td>41</td><td>&#39;A&#39;</td></tr><tr><td>90</td><td>5A</td><td>&#39;Z&#39;</td></tr><tr><td>97</td><td>61</td><td>&#39;a&#39;</td></tr><tr><td>122</td><td>7A</td><td>&#39;z&#39;</td></tr></tbody></table><p><strong>Important patterns:</strong></p><ul><li><code>&#39;A&#39;</code> = 65, <code>&#39;Z&#39;</code> = 90 (uppercase)</li><li><code>&#39;a&#39;</code> = 97, <code>&#39;z&#39;</code> = 122 (lowercase)</li><li>Difference between uppercase and lowercase = 32</li><li><code>&#39;0&#39;</code> = 48, <code>&#39;9&#39;</code> = 57 (digit characters)</li></ul><p><strong>Standard ASCII:</strong> 7 bits → 128 characters (0–127)<br><strong>Extended ASCII:</strong> 8 bits → 256 characters (0–255) — adds special characters</p><p><strong>Example — storing &#39;Hi&#39; in ASCII:</strong></p><ul><li>&#39;H&#39; = 72 = <code>01001000</code></li><li>&#39;i&#39; = 105 = <code>01101001</code></li></ul><p>So &#39;Hi&#39; = <code>01001000 01101001</code> (2 bytes)</p><hr><h2 id="unicode" tabindex="-1">Unicode <a class="header-anchor" href="#unicode" aria-label="Permalink to &quot;Unicode&quot;">​</a></h2><p>ASCII only covers English and basic symbols — it cannot represent Chinese, Arabic, Hindi, emoji, or thousands of other characters.</p><p><strong>Unicode</strong> is a universal standard that assigns a unique code point to every character in every writing system.</p><table tabindex="0"><thead><tr><th>Encoding</th><th>Bits per character</th><th>Characters possible</th><th>Notes</th></tr></thead><tbody><tr><td>ASCII</td><td>7 bits</td><td>128</td><td>English only</td></tr><tr><td>Extended ASCII</td><td>8 bits</td><td>256</td><td>Some European chars</td></tr><tr><td>Unicode (UTF-8)</td><td>1–4 bytes</td><td>1 112 064</td><td>Backwards compatible with ASCII</td></tr><tr><td>Unicode (UTF-16)</td><td>2–4 bytes</td><td>1 112 064</td><td>Used in Windows internally</td></tr><tr><td>Unicode (UTF-32)</td><td>4 bytes fixed</td><td>1 112 064</td><td>Fixed width, easier processing</td></tr></tbody></table><p><strong>Why Unicode matters:</strong></p><ul><li>Globalisation — websites need to display any language</li><li>Emoji are Unicode characters (<code>😀</code> = U+1F600)</li><li>Modern systems use UTF-8 by default</li></ul><hr><h2 id="encoding-images" tabindex="-1">Encoding Images <a class="header-anchor" href="#encoding-images" aria-label="Permalink to &quot;Encoding Images&quot;">​</a></h2><p>Images are stored as pixels. Each pixel&#39;s colour is stored as a binary number.</p><p><strong>Key terms:</strong></p><ul><li><strong>Resolution</strong> — width × height in pixels (e.g. 1920 × 1080)</li><li><strong>Colour depth</strong> — how many bits per pixel</li></ul><table tabindex="0"><thead><tr><th>Colour depth</th><th>Colours possible</th><th>Storage per pixel</th></tr></thead><tbody><tr><td>1-bit</td><td>2 (B&amp;W)</td><td>1 bit</td></tr><tr><td>4-bit</td><td>16</td><td>0.5 byte</td></tr><tr><td>8-bit</td><td>256</td><td>1 byte</td></tr><tr><td>16-bit</td><td>65 536</td><td>2 bytes</td></tr><tr><td><strong>24-bit</strong></td><td><strong>16 777 216</strong></td><td><strong>3 bytes</strong></td></tr><tr><td>32-bit</td><td>16 777 216 + transparency</td><td>4 bytes</td></tr></tbody></table><p><strong>True colour = 24-bit</strong> — 8 bits each for Red, Green, Blue (RGB).</p><p><strong>Storage calculation:</strong></p><p>Uncompressed image size = width × height × colour_depth_bits ÷ 8 (bytes)</p><p>Example: 1920 × 1080, 24-bit<br> = 1 920 × 1 080 × 24 ÷ 8 = 6 220 800 bytes ≈ 5.93 MB</p><hr><h2 id="encoding-audio" tabindex="-1">Encoding Audio <a class="header-anchor" href="#encoding-audio" aria-label="Permalink to &quot;Encoding Audio&quot;">​</a></h2><p>Audio is captured by <strong>sampling</strong> the analogue sound wave at regular intervals.</p><table tabindex="0"><thead><tr><th>Parameter</th><th>Meaning</th><th>CD quality</th></tr></thead><tbody><tr><td><strong>Sample rate</strong></td><td>Samples per second (Hz)</td><td>44 100 Hz</td></tr><tr><td><strong>Bit depth</strong></td><td>Bits per sample</td><td>16 bits</td></tr><tr><td><strong>Channels</strong></td><td>Mono (1) or stereo (2)</td><td>2 (stereo)</td></tr></tbody></table><p><strong>Storage = sample_rate × bit_depth × channels × seconds ÷ 8</strong></p><hr><h2 id="data-compression" tabindex="-1">Data Compression <a class="header-anchor" href="#data-compression" aria-label="Permalink to &quot;Data Compression&quot;">​</a></h2><p>Raw data is often much larger than necessary. Compression reduces file size.</p><table tabindex="0"><thead><tr><th>Type</th><th>Method</th><th>Quality change</th><th>Examples</th></tr></thead><tbody><tr><td><strong>Lossless</strong></td><td>Removes redundant data; fully recoverable</td><td>None — exact original</td><td>ZIP, PNG, FLAC</td></tr><tr><td><strong>Lossy</strong></td><td>Permanently removes detail human senses won&#39;t notice</td><td>Reduced (but usually acceptable)</td><td>JPEG, MP3, MP4</td></tr></tbody></table><p><strong>Why lossless for some files:</strong></p><ul><li>Text/programs: even one changed bit breaks the file — must be lossless</li><li>Medical images: can&#39;t lose any detail — lossless required</li></ul><p><strong>Why lossy is acceptable for media:</strong></p><ul><li>Human eyes/ears don&#39;t detect small quality reductions</li><li>File size reduction can be 10× to 100×</li></ul><hr><h2 id="data-representation-summary-table" tabindex="-1">Data Representation Summary Table <a class="header-anchor" href="#data-representation-summary-table" aria-label="Permalink to &quot;Data Representation Summary Table&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Data Type</th><th>Encoding Standard</th><th>Key Unit</th></tr></thead><tbody><tr><td>Text (English)</td><td>ASCII</td><td>1 byte per character</td></tr><tr><td>Text (international)</td><td>Unicode (UTF-8)</td><td>1–4 bytes per character</td></tr><tr><td>Integers</td><td>Binary (two&#39;s complement for negatives)</td><td>4 bytes (32-bit integer)</td></tr><tr><td>Images</td><td>RGB / colour depth</td><td>Bits per pixel</td></tr><tr><td>Audio</td><td>PCM sampling</td><td>Sample rate × bit depth × channels</td></tr><tr><td>Video</td><td>Frames × image encoding</td><td>Frame rate × frame size</td></tr><tr><td>Colour codes</td><td>Hexadecimal RGB</td><td><code>#RRGGBB</code></td></tr></tbody></table><hr><h2 id="key-terms" tabindex="-1">Key Terms <a class="header-anchor" href="#key-terms" aria-label="Permalink to &quot;Key Terms&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Term</th><th>Definition</th></tr></thead><tbody><tr><td><strong>Bit</strong></td><td>Single binary digit (0 or 1)</td></tr><tr><td><strong>Byte</strong></td><td>8 bits — basic unit of storage</td></tr><tr><td><strong>ASCII</strong></td><td>Standard 7-bit encoding for English characters</td></tr><tr><td><strong>Unicode</strong></td><td>Universal encoding standard for all world characters</td></tr><tr><td><strong>UTF-8</strong></td><td>Variable-width Unicode encoding; most common on the web</td></tr><tr><td><strong>Colour depth</strong></td><td>Number of bits used to represent one pixel&#39;s colour</td></tr><tr><td><strong>Resolution</strong></td><td>Number of pixels in an image (width × height)</td></tr><tr><td><strong>Sample rate</strong></td><td>Number of audio samples taken per second (Hz)</td></tr><tr><td><strong>Lossless compression</strong></td><td>Reduces size without losing any data</td></tr><tr><td><strong>Lossy compression</strong></td><td>Reduces size by permanently removing some data</td></tr><tr><td><strong>Pixel</strong></td><td>Smallest element of a digital image</td></tr><tr><td><strong>Hexadecimal</strong></td><td>Base-16 number system — compact binary representation</td></tr></tbody></table><hr><h2 id="exam-focus" tabindex="-1">Exam Focus <a class="header-anchor" href="#exam-focus" aria-label="Permalink to &quot;Exam Focus&quot;">​</a></h2><div class="important custom-block github-alert"><p class="custom-block-title">High-Frequency Questions</p><p></p><ol><li><p><strong>Convert decimal ↔ binary / hex</strong> — show all working; verify by converting back</p></li><li><p><strong>&quot;Give the ASCII value of [character]&quot;</strong> — memorise A=65, a=97, 0=48; calculate others by offset</p></li><li><p><strong>&quot;Calculate the uncompressed file size of an image&quot;</strong> — width × height × colour depth ÷ 8 for bytes</p></li><li><p><strong>&quot;Explain the difference between lossless and lossy compression. Give an example of each.&quot;</strong> — lossless = no quality loss (ZIP/PNG), lossy = some quality lost (JPEG/MP3)</p></li><li><p><strong>&quot;Why do we need Unicode when we have ASCII?&quot;</strong> — ASCII only covers 128 characters (English); Unicode supports all world languages + emoji + special characters</p></li></ol></div>`,93)])])}const g=e(s,[["render",n]]);export{b as __pageData,g as default};
